const items = $input.all();

// Se não tem posts, retorna vazio
if (!items.length) {
  return [{
    json: {
      tem_posts: false,
      mensagem: 'Nenhum post aguardando aprovação'
    }
  }];
}

// Pega apenas o PRIMEIRO post aguardando aprovação
// Como o JSON vem como array, precisa pegar items[0].json (que é o array), depois [0] (primeiro item do array)
const post = items[0].json?.[0] || items[0].json || items[0];

// Valida se o post tem os dados necessários
if (!post.id_post || !post.blog) {
  return [{
    json: {
      tem_posts: false,
      mensagem: 'Post inválido: faltam dados essenciais',
      debug: post // <-- adiciona isso para ver o que está vindo
    }
  }];
}

// Prepara as URLs das imagens (filtra vazias)
const imagens = [
  post.imagem1_url,
  post.imagem2_url,
  post.imagem3_url,
  post.imagem4_url,
  post.imagem5_url,
  post.imagem6_url,
  post.imagem7_url
].filter(url => url && url.trim() !== '');

// Verifica se tem pelo menos 1 imagem
if (!imagens.length) {
  return [{
    json: {
      tem_posts: false,
      mensagem: 'Post sem imagens válidas'
    }
  }];
}

// Retorna o post completo + metadados extras
return [{
  json: {
    ...post, // <-- inclui todos os campos originais do JSON
    tem_posts: true,
    quantidade_imagens: imagens.length,
    imagem_principal: imagens[0], // primeira imagem (capa)
    imagens: imagens, // lista com todas as imagens válidas
    data_processamento: new Date().toISOString(),
    mensagem: `Post ${post.id_post} preparado para análise do AI Agent`
  }
}];

// Pega o item atual (modo Run Once for Each Item)
const item = $input.item.json;

try {
  // Pega o conteúdo da resposta da IA
  let aiResponse = item.data || item.response || item.message || item.output || item;

  // Se vier como string, tenta limpar e parsear
  if (typeof aiResponse === 'string') {
    // Remove markdown se existir (```json ... ```)
    aiResponse = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    // Remove "json" no início se existir
    aiResponse = aiResponse.replace(/^json/, '').trim();

    // Tenta fazer parse do JSON
    aiResponse = JSON.parse(aiResponse);
  }

  // Se a resposta for um array, pega o primeiro elemento
  if (Array.isArray(aiResponse)) {
    aiResponse = aiResponse[0];
  }

  // Valida se tem os campos obrigatórios
  if (!aiResponse.id_post) {
    throw new Error('Campo id_post não encontrado na resposta da IA');
  }

  // Retorna a estrutura completa do objeto
  return {
    id_post: aiResponse.id_post,
    status: aiResponse.status,
    nota_final: aiResponse.nota_final,
    notas_detalhadas: {
      visual: aiResponse.notas_detalhadas.visual,
      legenda: aiResponse.notas_detalhadas.legenda,
      relevancia: aiResponse.notas_detalhadas.relevancia
    },
    categoria_visual: aiResponse.categoria_visual,
    categoria_legenda: aiResponse.categoria_legenda,
    categoria_relevancia: aiResponse.categoria_relevancia,
    justificativa: aiResponse.justificativa,
    pontos_fortes: aiResponse.pontos_fortes,
    pontos_fracos: aiResponse.pontos_fracos,
    recomendacao: aiResponse.recomendacao
  };

} catch (error) {
  // Em caso de erro, retorna o erro estruturado
  return {
    erro: true,
    mensagem: error.message,
    item_original: item
  };
}

try {
// Obtém a resposta da IA Vision
let raw = $input.item.json.content;
// Limpeza: remove \n, escapes e espaços extras
raw = raw
.replace(/\n/g, '')
.replace(/\r/g, '')
.replace(/\"/g, '"')
.replace(/\s+/g, ' ')
.trim();
// Remove markdown se vier com json   raw = raw.replace(/json|```/g, '').trim();
// Tenta extrair apenas o objeto JSON (entre { e })
const start = raw.indexOf('{');
const end = raw.lastIndexOf('}') + 1;
if (start === -1 || end === 0) {
throw new Error('JSON não encontrado na resposta');
}
const jsonStr = raw.substring(start, end);
// Faz o parse do JSON
const data = JSON.parse(jsonStr);
// Recupera dados do post original
const post = $('Prepara Post para Análise').item.json;
// Retorna tudo junto
return {
json: {
// 🔹 Dados originais do post
id_post: post.id_post,
Titulo: post.Titulo,
Legenda: post.Legenda_Instagram,
quantidade_imagens: post.quantidade_imagens,
imagens: post.imagens,
imagem_principal: post.imagem_principal,
data_criacao: post.data_criacao,
status_atual: post.Status,
  // 🔹 Resultados da IA Vision
  decisao_geral: data.decisao_geral,
  imagens_aprovadas: data.imagens_aprovadas,
  imagens_rejeitadas: data.imagens_rejeitadas,
  imagens_analisadas: data.imagens_analisadas || 6,
  recomendacao_final: data.recomendacao_final,
  analise_detalhada: data.analise_detalhada,

  // 🔹 Flags de controle
  precisa_regerar: data.recomendacao_final === "REGERAR_IMAGENS",
  pode_publicar: data.decisao_geral === "APROVADO",

  // 🔹 Metadados de controle
  data_processamento: new Date().toISOString(),
  origem: "Análise Visual (IA Vision)",
  erro: false
}
};
} catch (error) {
// Em caso de erro, retorna os dados originais + flag de erro
const post = $('Prepara Post para Análise').item.json;
return {
json: {
// Dados do post
id_post: post.id_post,
Titulo: post.Titulo,
Legenda: post.Legenda_Instagram,
quantidade_imagens: post.quantidade_imagens,
  // Erro
  erro: true,
  erro_mensagem: error.message,
  erro_resposta_original: $input.item.json.content,

  // Valores padrão para não quebrar o fluxo
  decisao_geral: "ERRO",
  imagens_aprovadas: 0,
  imagens_rejeitadas: 0,
  imagens_analisadas: 6,
  recomendacao_final: "REVISAR_MANUALMENTE",
  analise_detalhada: [],
  precisa_regerar: true,
  pode_publicar: false,

  data_processamento: new Date().toISOString(),
  origem: "Análise Visual (IA Vision) - ERRO"
}
};
}
